#include <bits/stdc++.h>
using namespace std;
int n , m , x , s;
int a[ 505 ];
struct node {
	int v , l , c;
};
struct edge {
	int v , w;
	bool operator < ( const edge &x ) const {
		return w > x.w;
	}
};
priority_queue < edge > pq;
int dis[ 505 ] , vis[ 505 ];
vector < node > e[ 1000005 ];
void dij( int x ) {
	memset( vis , false , sizeof( vis ) );
	for( int i = 0 ; i <= n ; i++ )
		dis[ i ] = 1e9;
	dis[ s ] = 0;
	pq.push( { s , 0 } );
	while( !pq.empty() ) {
		int mi = pq.top().v;
		pq.pop();
		if( vis[ mi ] )
			continue;
		vis[ mi ] = 1;
		for( auto i : e[ mi ] ) {
			int v = i.v , l = i.l;
			if ( i.c >= x && dis[ v ] > dis[ mi ] + l ) {
				dis[ v ] = dis[ mi ] + l;
				pq.push( { v , dis[ v ] } ); 
			}
		}
	}
}
int main() {
	cin >> n >> m >> x;
	s = 1;
	for( int i = 1 , u , v , l , c ; i <= m ; i++ ) {
		cin >> u >> v >> l >> c;
		e[ u ].push_back( { v , l , c } );
		e[ v ].push_back( { u , l , c } );
		a[ i ] = c;
	}
	int ans = INT_MAX;
	for( int i = 1 ; i <= m ; i++ ) {
		dij( a[ i ] );
		if( dis[ n ] != 1e9 )
		    ans = min( ans , dis[ n ] + x / a[ i ] ); 
	}
	cout << ans;
	return 0;
}
